import React, { useState } from "react";

const images = [
  "https://images.unsplash.com/photo-1581092580497-e0d23cbdf1dc?w=600",
  "https://images.unsplash.com/photo-1603732551658-5fabbafa84eb?w=600",
  "https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=600",
  "https://images.unsplash.com/photo-1603791440384-56cd371ee9a7?w=600",
  "https://images.unsplash.com/photo-1581091870627-3f3b8f1f0d5e?w=600",
];



const baseItems = [
  { name: "LED Bulb", desc: "Energy saving light bulb", image: "https://energymall.ng/wp-content/uploads/2019/07/Nexlite-9watts-12v-DC-bulb-2.jpg" },
  { name: "Electrical Wire Roll", desc: "Copper insulated wire", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQdE88hhq84tX0Ajuo4P8doabD8Euyi9_0SWg&s" },
  { name: "Soldering Iron", desc: "Precision solder tool", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSomwEoMpzCdbKax5SlGGwM56xT4EUVPWi3nw&s" },
  { name: "Switch Panel", desc: "Wall mounted control switches", image: "data:image/jpeg;base64," },
  { name: "Power Socket", desc: "Standard wall socket outlet", image: "data:image/jpeg;base64," },

  { name: "Extension Cord", desc: "Multi-plug extension cable", image: "data:image/jpeg;base64," },
  { name: "Circuit Breaker", desc: "Electrical safety breaker", image: "data:image/jpeg;base64," },
  { name: "Voltage Tester", desc: "Checks electric current safely", image: "data:image/jpeg;base64," },
  { name: "Fuse Box", desc: "Power distribution unit", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ-pe7oIDtgjJFxFJwfQ7LDKNApFrb8XhtZHw&s" },
  { name: "Cable Clips", desc: "Wire management accessories", image: "data:image/jpeg;base64,"},
  { name: "Smart Plug", desc: "WiFi controlled plug", image: "data:image/jpeg;base64," },
  { name: "Electric Drill", desc: "Heavy duty drilling tool", image: "data:image/jpeg;base64,"},
  { name: "Wire Stripper", desc: "Cable stripping tool", image: "data:image/jpeg;base64," },
  { name: "Multimeter", desc: "Voltage and current tester", image: "data:image/jpeg;base64," },
  { name: "Cable Reel", desc: "Heavy duty cable storage", image: "data:image/jpeg;base64," },

  { name: "LED Strip Lights", desc: "Decorative lighting strips", image: "data:image/jpeg;base64," },
  { name: "Smart Bulb", desc: "Color changing bulb", image: "data:image/jpeg;base64," },
  { name: "Fan Motor", desc: "Replacement motor", image: "data:image/jpeg;base64," },
  { name: "Battery Pack", desc: "Rechargeable battery unit", image: "data:image/jpeg;base64," },
  { name: "Solar Charger", desc: "Portable solar panel", image: "data:image/jpeg;base64," },
];
const products = Array.from({ length: 100 }, (_, i) => {
  const item = baseItems[i % baseItems.length];

  return {
    id: i + 1,
    name: `${item.name} ${i + 1}`,
    description: item.desc,
    price: Math.floor(Math.random() * 90 + 10),
    image: item.image,
  };
});

export default function Products() {
  const [search, setSearch] = useState("");
  const [cart, setCart] = useState([]);
  const [page, setPage] = useState(1);
  const [showCart, setShowCart] = useState(false);

  const itemsPerPage = 20;

  const filtered = products.filter((p) =>
    p.name.toLowerCase().includes(search.toLowerCase())
  );

  const start = (page - 1) * itemsPerPage;
  const paginated = filtered.slice(start, start + itemsPerPage);
  const totalPages = Math.ceil(filtered.length / itemsPerPage);

  const addToCart = (item) => {
    setCart((prev) => [...prev, item]);
  };

  const removeFromCart = (id) => {
    setCart((prev) => prev.filter((item) => item.id !== id));
  };

  return (
    <div style={{ background: "#f5f5f5", minHeight: "100vh" }}>

      {/*  BANNER */}
      <div
        style={{
          position: "relative",
          height: "200px",
          backgroundImage:
            "url('https://images.unsplash.com/photo-1581092160607-ee22621dd758?w=1200')",
          backgroundSize: "cover",
          backgroundPosition: "center",
        }}
      >
        <div
          style={{
            position: "absolute",
            inset: 0,
            background: "rgba(0,0,0,0.5)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          <h1
            style={{
              color: "white",
              fontSize: "40px",
              fontWeight: "bold",
              letterSpacing: "3px",
            }}
          >
            PRODUCTS
          </h1>
        </div>
      </div>

      {/* SEARCH + CART BUTTON */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: "10px",
          marginTop: "15px",
          flexWrap: "wrap",
        }}
      >
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search products..."
          style={{
            padding: "10px",
            width: "250px",
            borderRadius: "8px",
            border: "1px solid #ccc",
          }}
        />

        <button
          onClick={() => setShowCart(!showCart)}
          style={{
            padding: "10px 15px",
            background: "#111",
            color: "#fff",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer",
          }}
        >
          View Cart ({cart.length})
        </button>
      </div>

      {/* CART PANEL */}
      {showCart && (
        <div
          style={{
            position: "fixed",
            right: "20px",
            top: "120px",
            width: "250px",
            background: "#fff",
            padding: "10px",
            borderRadius: "10px",
            boxShadow: "0 5px 15px rgba(0,0,0,0.2)",
            zIndex: 1000,
          }}
        >
          <h3>Cart</h3>

          {cart.length === 0 && <p>No items</p>}

          {cart.map((item) => (
            <div
              key={item.id}
              style={{
                display: "flex",
                justifyContent: "space-between",
                fontSize: "12px",
                marginBottom: "5px",
              }}
            >
              {item.name}
              <button
                onClick={() => removeFromCart(item.id)}
                style={{
                  border: "none",
                  background: "transparent",
                  color: "red",
                  cursor: "pointer",
                }}
              >
                ✕
              </button>
            </div>
          ))}
        </div>
      )}

      {/* PRODUCTS GRID */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(auto-fit, minmax(170px, 1fr))",
          gap: "15px",
          padding: "20px",
        }}
      >
        {paginated.map((p) => (
          <div
            key={p.id}
            style={{
              background: "#fff",
              borderRadius: "10px",
              overflow: "hidden",
              boxShadow: "0 3px 10px rgba(0,0,0,0.1)",
            }}
          >
            <img
              src={p.image}
              alt={p.name}
              style={{ width: "100%", height: "140px", objectFit: "cover" }}
            />

            <div style={{ padding: "10px" }}>
              <h3 style={{ fontSize: "13px" }}>{p.name}</h3>
              <p style={{ fontSize: "11px", color: "#666" }}>
                {p.description}
              </p>
              <p style={{ fontWeight: "bold" }}>${p.price}</p>

              {/* BIGGER + CLEAN BUTTON */}
              <button
                onClick={() => addToCart(p)}
                style={{
                  width: "100%",
                  padding: "12px",
                  marginTop: "8px",
                  border: "none",
                  borderRadius: "6px",
                  background: "#000",
                  color: "#fff",
                  fontSize: "15px",
                  fontWeight: "bold",
                  cursor: "pointer",
                }}
              >
                Add to Cart
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* PAGINATION */}
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: "8px",
          paddingBottom: "20px",
          flexWrap: "wrap",
        }}
      >
        {Array.from({ length: totalPages }, (_, i) => (
          <button
            key={i}
            onClick={() => setPage(i + 1)}
            style={{
              padding: "6px 10px",
              borderRadius: "6px",
              border: "1px solid #ccc",
              background: page === i + 1 ? "#111" : "#fff",
              color: page === i + 1 ? "#fff" : "#111",
              cursor: "pointer",
            }}
          >
            {i + 1}
          </button>
        ))}
      </div>
    </div>
  );
}